import{t as e}from"./ProjectPage-CIktH849.js";import{E as t}from"./index-v__OI8KD.js";var n=t(),r={code:`Thread 002`,title:`POFIN`,question:`왜 좋아하는 작품인데 이야기할 사람이 없을까?`,type:`팀 프로젝트 · UXUI 디자인`,contribution:[`기획 · 사용자 리서치`,`UX/UI 디자인`,`프로토타이핑`],period:`2026.06~진행 중`,overview:`POFIN은 같은 작품을 보는 사람들이 스포일러 걱정 없이 감상을 기록하고 공유할 수 있는 콘텐츠 커뮤니티 서비스입니다. 사용자의 시청 진도를 기준으로 콘텐츠를 제공하여, 함께 감상하는 경험을 더욱 자연스럽게 이어갈 수 있도록 설계했습니다.`,sections:[{id:`question`,label:`Question`,title:`왜 좋아하는 작품인데 이야기할 사람이 없을까?`,body:`감상을 나누고 싶지만 서로의 시청 진도가 달라 스포일러를 걱정하게 됩니다. 우리는 이 문제를 해결하면서도 함께 보고 있다는 연결감을 만들 수 있는 방법을 고민했습니다.`},{id:`problem`,label:`Problem Discovery`,bullets:[`사용자 인터뷰를 통해 사람들이 감상을 공유하지 않는 가장 큰 이유는 스포일러에 대한 부담이라는 점을 발견했습니다. 또한 같은 작품을 보고 있어도 각자의 시청 속도가 달라 대화를 포기하거나 감상을 혼자 기록하는 경우가 많았습니다.`]},{id:`research`,label:`Research`,body:`20~30대 콘텐츠 소비자를 대상으로 설문조사와 심층 인터뷰를 진행했습니다. 감상 공유 시 가장 큰 불편은 스포일러에 대한 부담이며, 같은 작품을 보는 사람과 소통하고 싶은 니즈와 감상을 기록하거나 다시 찾아보고 싶은 경험을 다수 확인했습니다.`},{id:`insight`,label:`Insight`,title:`사람들은 ‘스포 걱정 없는 같은 진도의 친구’를 원한다`,body:`사용자가 원하는 것은 단순한 리뷰 서비스가 아니라, '내가 본 만큼만 안전하게 이야기할 수 있는 공간' 이었습니다. 스포일러 걱정 없이 같은 진도의 사람들과 감상을 나누는 경험이 서비스의 핵심 가치라고 판단했습니다.`},{id:`solution`,label:`Solution`,title:`진도 기반의 작품 커뮤니티, POFIN`,body:`사용자가 원하는 것은 단순한 리뷰 서비스가 아니라, '내가 본 만큼만 안전하게 이야기할 수 있는 공간' 이었습니다. 스포일러 걱정 없이 같은 진도의 사람들과 감상을 나누는 경험이 서비스의 핵심 가치라고 판단했습니다,또한 감상 기록, 리액션, 광장 기능을 통해 같은 작품을 보는 사람들과 자연스럽게 연결되는 경험을 제공합니다. `},{id:`ia`,label:`Information Architecture`,bullets:[`작품 등록 및 시청 진도 관리`,`작품별 감상 공간`,`장르별 광장 커뮤니티`,`개인 서재 및 기록 관리`,`사용자는 작품을 등록한 뒤 자신의 진도에 맞는 감상만 확인할 수 있습니다.`]},{id:`core`,label:`Core Features`,bullets:[`진도 기반 스포일러 차단`,`작품별 감상 기록`,`같은 작품 시청자와 소통`,`나만의 감상 아카이브`,`장르별 광장 커뮤니티`]},{id:`ui`,label:`UI Design`,body:` 픽셀아트 기반의 아기자기한 분위기를 적용해 덕질하는 즐거움을 표현했습니다. 보라 계열의 컬러와 캐릭터 '포피'를 활용하여 친근한 브랜드 경험을 만들고, 복잡한 기능도 직관적으로 사용할 수 있도록 단순한 구조로 설계했습니다`},{id:`outcome`,label:`Outcome`,bullets:[`프로토타입 사용자 12명 중 11명이 ‘스포 걱정 없이 이야기할 수 있어 좋다’고 응답.`,`‘같은 회차 라운지’ 진입률 78%, 평균 체류 시간 9분.`,`‘작품을 본 직후 이야기할 수 있는 곳이 생겼다’는 피드백.`]},{id:`retro`,label:`Retrospective`,body:`이번 프로젝트를 통해 사용자 경험은 기능을 추가하는 것이 아니라 사용자가 불편함을 느끼는 순간을 발견하는 것에서 시작된다는 점을 배웠습니다. 앞으로도 사람들의 작은 불편과 감정을 발견하고, 더 자연스럽고 오래 사용할 수 있는 경험을 만드는 디자이너가 되고자 합니다.`}],next:{to:`/graduation`,title:`Graduation Project`,question:`왜 우리는 애써 둥글게 살아야 할까?`}},i=()=>(0,n.jsx)(e,{meta:r});export{i as component};